{"type": "email", "id": "email_001", "subject": "CRM Software Budget Inquiry", "from": "amanda.lee@elexionautomotive.com", "from_name": "Amanda Lee", "to": ["michael.jensen@elexionautomotive.com"], "cc": [], "date": "2025-01-05 09:30:00", "body": "Dear Michael,

